#!/bin/bash

# ==============================================================================
# Script: run_ratio_experiments.sh
# Purpose: Automate training + testing for the 4 synthetic ratios (25%, 50%, 100%, 200%)
#          generated by mix_training_data_multivariate.sh.
#          Logic: For each appliance, run Baseline first, then the 4 synthetic cases.
# ==============================================================================

PROJECT_ROOT="$(cd "$(dirname "$0")" && pwd)"
cd "$PROJECT_ROOT"

# --- Setup Python Environment (Dynamic Detection) ---
if [ -f "/root/anaconda3/envs/nilm_main/bin/python3" ]; then
    PYTHON="/root/anaconda3/envs/nilm_main/bin/python3"
    ENV_LIB="/root/anaconda3/envs/nilm_main/lib"
elif [ -f "/home/raymond/miniconda3/envs/nilm_main/bin/python3" ]; then
    PYTHON="/home/raymond/miniconda3/envs/nilm_main/bin/python3"
    ENV_LIB="/home/raymond/miniconda3/envs/nilm_main/lib"
else
    PYTHON="python3"
    ENV_LIB=""
fi

# Fix: libstdc++.so.6 version issue (CXXABI_1.3.15 not found)
if [ -n "$ENV_LIB" ]; then
    export LD_LIBRARY_PATH="$ENV_LIB:$LD_LIBRARY_PATH"
fi

# --- Fix: libdevice.10.bc for TF XLA ---
TRITON_LIBDEVICE="$($PYTHON -c 'import triton; import os; print(os.path.join(os.path.dirname(triton.__file__), "backends/nvidia/lib/libdevice.10.bc"))' 2>/dev/null)"
if [ -f "$TRITON_LIBDEVICE" ]; then
    CUDA_DATA_DIR="/tmp/xla_cuda_data_ratio_$$"
    mkdir -p "$CUDA_DATA_DIR/nvvm/libdevice"
    ln -sf "$TRITON_LIBDEVICE" "$CUDA_DATA_DIR/nvvm/libdevice/libdevice.10.bc"
    export XLA_FLAGS="--xla_gpu_cuda_data_dir=$CUDA_DATA_DIR"
fi

export TF_CPP_MIN_LOG_LEVEL=2

# --- Appliances ---
USER_INPUT="$1"
if [ "$USER_INPUT" == "all" ] || [ -z "$USER_INPUT" ]; then
    APPLIANCES=("fridge" "microwave" "kettle" "dishwasher" "washingmachine")
else
    APPLIANCES=("$USER_INPUT")
fi

# --- Experiment Parameters ---
RATIOS=("25%" "50%" "100%" "200%")
EPOCHS=100
BATCH_SIZE=2048
TRAIN_PERCENT="20"

# --- Paths ---
DATA_DIR="$PROJECT_ROOT/created_data/UK_DALE/"
NILM_DIR="$PROJECT_ROOT/NILM-main"
MODELS_ROOT="$NILM_DIR/models/EasyS2S/UK_DALE"

# --- Result storage ---
declare -A RESULTS
declare -a CONFIG_ORDER

# --- Helper: run one train+test experiment ---
run_experiment() {
    local app=$1
    local train_filename=$2
    local origin_model=$3
    local config_key=$4

    local model_path="$MODELS_ROOT/${train_filename}_model"
    local weight_file="${model_path}_weights.h5"

    echo ""
    echo "------------------------------------------------------------"
    echo " APP: $app | $config_key | origin_model=$origin_model"
    echo "------------------------------------------------------------"

    if [ -f "$weight_file" ]; then
        echo "[RESUME] Found existing model. Skipping training."
    else
        echo "[TRAIN]"
        cd "$NILM_DIR"
        $PYTHON EasyS2S_train.py \
            --appliance_name "$app" \
            --n_epoch $EPOCHS \
            --batchsize $BATCH_SIZE \
            --datadir "$DATA_DIR" \
            --train_filename "$train_filename" \
            --origin_model "$origin_model" \
            --dataset_name "UK_DALE" \
            --train_percent "$TRAIN_PERCENT"
        
        if [ $? -ne 0 ]; then
            RESULTS["${config_key}|${app}"]="FAIL"
            cd "$PROJECT_ROOT"; return
        fi
    fi

    echo "[TEST]"
    TMP_TEST_LOG="/tmp/ratio_test_$$.log"
    cd "$NILM_DIR"
    $PYTHON EasyS2S_test.py \
        --appliance_name "$app" \
        --datadir "$DATA_DIR" \
        --train_filename "$train_filename" \
        --origin_model "$origin_model" \
        --dataset_name "UK_DALE" \
        --train_percent "$TRAIN_PERCENT" 2>&1 | tee "$TMP_TEST_LOG"
    
    MAE=$(grep -oP "MAE:\s*\K[0-9]*\.?[0-9]+" "$TMP_TEST_LOG" | head -1)
    rm -f "$TMP_TEST_LOG"
    RESULTS["${config_key}|${app}"]="${MAE:-N/A}"
    cd "$PROJECT_ROOT"
}

# --- Helper: Print Table ---
print_summary_table() {
    local col_w=14
    echo ""
    echo "================================================================"
    echo "  RATIO EXPERIMENTS MAE SUMMARY"
    echo "================================================================"
    local header="Configuration                  "
    for local_app in "${APPLIANCES[@]}"; do
        printf -v col "%-${col_w}s" "${local_app}"; header+="| ${col}"
    done
    echo "$header"
    local sep=""; local sep_len=${#header}; printf -v sep '%*s' "$sep_len" ''; echo "${sep// /-}"
    for config_key in "${CONFIG_ORDER[@]}"; do
        printf "%-31s" "$config_key"
        for local_app in "${APPLIANCES[@]}"; do
            local val="${RESULTS["${config_key}|${local_app}"]:-...}"
            if [[ "$val" =~ ^[0-9]*\.?[0-9]+$ ]]; then printf "| %-14.2f" "$val"
            else printf "| %-14s" "$val"; fi
        done
        echo ""
    done
    echo "${sep// /-}"; echo ""
}

# --- Build Config Order ---
CONFIG_ORDER+=("Baseline (Real Only)          ")
for r in "${RATIOS[@]}"; do
    CONFIG_ORDER+=("Synthetic ${r}                ")
done

# --- Main Loop ---
for app in "${APPLIANCES[@]}"; do
    # 1. Baseline (Compatible with standard ukdale naming)
    # The baseline for ratios is the standard 200k real training set
    TRAIN_FILENAME="${app}_training_" 
    run_experiment "$app" "$TRAIN_FILENAME" "TRUE" "Baseline (Real Only)          "
    print_summary_table

    # 2. Ratio Cases (Generated by mix_training_data_multivariate.sh)
    for r in "${RATIOS[@]}"; do
        CONFIG_KEY="Synthetic ${r}                "
        TRAIN_FILENAME="${app}_training_synthetic_${r}"
        
        # Enforce TRUE for all cases
        ORIGIN_MODEL="TRUE"

        run_experiment "$app" "$TRAIN_FILENAME" "$ORIGIN_MODEL" "$CONFIG_KEY"
        print_summary_table
    done
done

echo "Cleaning up XLA temp files..."
rm -rf "$CUDA_DATA_DIR"
echo "DONE: All ratio experiments finished."
